1	/**
2	 * Core OracleAIClient types.
3	 *
4	 * Source of truth for the shapes used by every adapter, the context compiler,
5	 * and the model router. Per docs/oracle/02-provider-native-ai-architecture.md.
6	 *
7	 * Dynamic content (current user message, current chunk, retry suffix) must
8	 * NEVER be placed before the stable cacheable prefix. PromptBlock.kind is the
9	 * primary signal that ContextCompiler uses to order blocks correctly.
10	 */
11	
12	export type OracleTaskType =
13	  | 'interview_chat'
14	  | 'message_claim_extraction'
15	  | 'document_claim_extraction'
16	  | 'contradiction_detection'
17	  | 'brain_synthesis'
18	  | 'gap_generation'
19	  | 'admin_explanation'
20	  | 'validation_repair'
21	  | 'model_capability_discovery';
22	
23	/**
24	 * The kind tag controls block ordering for provider-native cache friendliness.
25	 * Stable blocks must appear before semi-stable, which must appear before
26	 * retrieved, which must appear before dynamic.
27	 */
28	export type PromptBlockKind =
29	  | 'stable_system'
30	  | 'stable_schema'
31	  | 'stable_tool_definition'
32	  | 'semi_stable_domain_context'
33	  | 'retrieved_context'
34	  | 'dynamic_input'
35	  | 'output_contract';
36	
37	export interface PromptBlock {
38	  /** Stable identifier, unique within a plan. */
39	  id: string;
40	  /** Human-readable label for observability. */
41	  label: string;
42	  kind: PromptBlockKind;
43	  content: string;
44	  /** Content hash (sha256 over content). Stable per content. */
45	  hash: string;
46	  tokenEstimate?: number;
47	  cacheEligible: boolean;
48	  /** Free-form reason this block was included; useful for observability. */
49	  reasonIncluded: string;
50	}
51	
52	export interface OutputContract {
53	  name: string;
54	  schemaHash: string;
55	  mode: 'native_json_schema' | 'tool_call' | 'schema_prompt_plus_validator';
56	}
57	
58	/**
59	 * A compiled prompt plan ready to be dispatched to a provider adapter.
60	 * Includes block-level data + opaque hashes for cache + observability.
61	 */
62	export interface OraclePromptPlan {
63	  taskType: OracleTaskType;
64	  routeId: string;
65	  promptVersion: string;
66	  schemaVersion?: string;
67	  blocks: PromptBlock[];
68	  outputContract?: OutputContract;
69	  metadata: PromptPlanMetadata;
70	}
71	
72	export interface PromptPlanMetadata {
73	  /** Hash over every stable_* block in order. The cache key. */
74	  stablePrefixHash: string;
75	  semiStableContextHash?: string;
76	  retrievedContextHash?: string;
77	  dynamicInputHash: string;
78	  toolSchemaHash?: string;
79	  outputSchemaHash?: string;
80	  includedMessageIds?: string[];
81	  includedDocumentChunkIds?: string[];
82	  includedClaimIds?: string[];
83	  includedGapIds?: string[];
84	  includedContradictionIds?: string[];
85	  retrievalPlanId?: string;
86	  selectedDomains?: string[];
87	  selectedSourceTypes?: string[];
88	  selectedProcessStages?: string[];
89	  selectedEntityIds?: string[];
90	}
91	
92	/**
93	 * Normalized usage shape — what UsageLogger writes to `model_runs`.
94	 * Each provider returns slightly different fields; UsageNormalizer maps
95	 * them all into this shape.
96	 */
97	export interface OracleUsage {
98	  inputTokens?: number;
99	  /** Tokens read from cache. Provider-native. */
100	  cachedInputTokens?: number;
101	  /** Tokens written to cache (Anthropic explicit, Vertex explicit creates). */
102	  cacheWriteTokens?: number;
103	  outputTokens?: number;
104	  /** Reasoning/thinking tokens where the provider exposes them. */
105	  reasoningTokens?: number;
106	  totalCostUsd?: string;
107	  latencyMs: number;
108	  providerRequestId?: string;
109	  /** Raw provider usage object preserved for audit and debug. */
110	  rawUsageJson?: unknown;
111	}
112	
113	export interface OracleRunRouteMetadata {
114	  routeId?: string;
115	  provider?: string;
116	  modelId?: string;
117	  fellBackFromRouteId?: string;
118	  fallbackReason?: string;
119	}
120	
121	/** Result of a generateText call. */
122	export interface OracleTextResult extends OracleRunRouteMetadata {
123	  text: string;
124	  usage: OracleUsage;
125	  rawResponse: unknown;
126	}
127	
128	/** Result of a generateObject call (structured output). */
129	export interface OracleObjectResult<T> extends OracleRunRouteMetadata {
130	  object: T;
131	  usage: OracleUsage;
132	  rawResponse: unknown;
133	}
