1	/**
2	 * OracleAIClient — the single production gateway for all Oracle model calls.
3	 *
4	 * After R2 is in place, NO route handler, worker, or admin component may
5	 * call a provider SDK directly. Everything goes through this client:
6	 *
7	 *     OracleAIClient
8	 *       -> ContextCompiler   (assemble the OraclePromptPlan)
9	 *       -> ModelRouter       (pick adapter, dispatch with fallback)
10	 *       -> ProviderAdapter   (Anthropic / Vertex / OpenAI / Mock)
11	 *
12	 * R2 ships the wiring. R3+ replaces the stub adapters with real SDK calls
13	 * and adds usage logging into `model_runs`.
14	 *
15	 * Test mode (`mode: 'test'`) registers MockProviderAdapter for every
16	 * provider, so the entire pipeline can be exercised without API keys.
17	 */
18	
19	import type { ZodType } from 'zod';
20	import { getContextCompiler, type CompileArgs } from '../context/context-compiler';
21	import { ModelRouter, type ProviderAdapterMap } from '../routing/model-router';
22	import { AnthropicAdapter } from '../providers/anthropic-adapter';
23	import { VertexGeminiAdapter } from '../providers/vertex-gemini-adapter';
24	import { OpenAIAdapter } from '../providers/openai-adapter';
25	import { MockProviderAdapter } from '../providers/mock-adapter';
26	import {
27	  getStructuredOutputValidator,
28	  type ValidationResult,
29	} from '../validation/structured-output-validator';
30	import type {
31	  OracleObjectResult,
32	  OraclePromptPlan,
33	  OracleTextResult,
34	} from './types';
35	
36	export type OracleAIClientMode = 'production' | 'test';
37	
38	export interface OracleAIClientOptions {
39	  mode?: OracleAIClientMode;
40	  /**
41	   * Override the adapter map. When mode is 'test' and no override is given,
42	   * mock adapters are registered for every provider.
43	   */
44	  adapters?: ProviderAdapterMap;
45	  /** When true, the router auto-dispatches to the route's Fallback on transient errors. Default true. */
46	  fallbackOnError?: boolean;
47	}
48	
49	export interface RunTextArgs extends CompileArgs {
50	  /**
51	   * Optional generic escape hatch passed through to the provider adapter.
52	   * The chat route (R8+) uses this for tool calling, multi-turn message
53	   * arrays, stopWhen step caps, and temperature. Adapters that don't
54	   * support a given option ignore it silently.
55	   */
56	  providerOptions?: Record<string, unknown>;
57	}
58	
59	export interface RunObjectArgs<TSchema> extends CompileArgs {
60	  schema: ZodType<TSchema>;
61	  /**
62	   * Optional generic escape hatch passed through to the provider adapter.
63	   * Used for cache-control hints, multi-turn context overrides, and other
64	   * provider-specific knobs that don't belong on OraclePromptPlan itself.
65	   */
66	  providerOptions?: Record<string, unknown>;
67	}
68	
69	export interface RunObjectResult<TSchema> extends OracleObjectResult<TSchema> {
70	  /** Result of validating the raw model output against the supplied Zod schema. */
71	  validation: ValidationResult<TSchema>;
72	}
73	
74	export class OracleAIClient {
75	  private readonly compiler = getContextCompiler();
76	  private readonly router: ModelRouter;
77	  private readonly validator = getStructuredOutputValidator();
78	  readonly mode: OracleAIClientMode;
79	
80	  constructor(opts: OracleAIClientOptions = {}) {
81	    this.mode = opts.mode ?? 'production';
82	    const adapters: ProviderAdapterMap =
83	      opts.adapters ??
84	      (this.mode === 'test'
85	        ? {
86	            anthropic: new MockProviderAdapter({ provider: 'anthropic' }),
87	            vertex: new MockProviderAdapter({ provider: 'vertex' }),
88	            openai: new MockProviderAdapter({ provider: 'openai' }),
89	          }
90	        : {
91	            anthropic: new AnthropicAdapter(),
92	            vertex: new VertexGeminiAdapter(),
93	            openai: new OpenAIAdapter(),
94	          });
95	    this.router = new ModelRouter({ adapters, fallbackOnError: opts.fallbackOnError });
96	  }
97	
98	  /** Compile a plan without running it. Useful for tests and for previewing the request. */
99	  compile(args: CompileArgs): OraclePromptPlan {
100	    return this.compiler.compile(args);
101	  }
102	
103	  /** Compile + dispatch a freeform text call (e.g. interview chat). */
104	  async runText(args: RunTextArgs): Promise<OracleTextResult> {
105	    const plan = this.compile(args);
106	    return this.router.generateText(plan, args.providerOptions);
107	  }
108	
109	  /** Compile + dispatch a structured-output call. Output is validated against the supplied Zod schema. */
110	  async runObject<TSchema>(args: RunObjectArgs<TSchema>): Promise<RunObjectResult<TSchema>> {
111	    const plan = this.compile(args);
112	    const result = await this.router.generateObject<ZodType<TSchema>, TSchema>(
113	      plan,
114	      args.schema,
115	      args.providerOptions,
116	    );
117	    const validation = this.validator.validate(args.schema, result.object);
118	    return { ...result, validation };
119	  }
120	}
121	
122	/** Singleton convenience for production code. Construct your own for tests. */
123	let cached: OracleAIClient | null = null;
124	export function getOracleAIClient(): OracleAIClient {
125	  if (!cached) cached = new OracleAIClient();
126	  return cached;
127	}
128	
129	/** Reset the cached singleton. Test-only. */
130	export function __resetOracleAIClientForTests(): void {
131	  cached = null;
132	}
