1	/**
2	 * PromptBlock helpers — content hashing, token estimation, kind ordering.
3	 *
4	 * The hash function MUST be deterministic across processes. Cache hit ratio
5	 * depends on the stable prefix hashing the same way every time, every place.
6	 */
7	
8	import { createHash } from 'node:crypto';
9	import type { PromptBlock, PromptBlockKind } from '../client/types';
10	
11	/** Deterministic sha256 over a string, returned as hex. */
12	export function hashContent(content: string): string {
13	  return createHash('sha256').update(content, 'utf8').digest('hex');
14	}
15	
16	/** Hash over the ordered list of block hashes — used as a composite key. */
17	export function hashBlockSequence(blocks: PromptBlock[]): string {
18	  return createHash('sha256').update(blocks.map((b) => b.hash).join('|'), 'utf8').digest('hex');
19	}
20	
21	/**
22	 * Rough token estimate. 4 chars/token is the well-known approximation; we
23	 * pick it deliberately because it's predictable and provider-agnostic. Real
24	 * usage numbers are reconciled later via OracleUsage.inputTokens from the
25	 * provider response.
26	 */
27	export function estimateTokens(content: string): number {
28	  return Math.ceil(content.length / 4);
29	}
30	
31	/**
32	 * Order in which kinds must be emitted to the provider. Stable kinds come
33	 * first so providers' prefix caches (Anthropic auto, Vertex implicit, OpenAI
34	 * automatic prefix) can recognize the stable prefix across calls.
35	 */
36	const KIND_ORDER: Record<PromptBlockKind, number> = {
37	  stable_system: 0,
38	  stable_tool_definition: 1,
39	  stable_schema: 2,
40	  output_contract: 3,
41	  semi_stable_domain_context: 4,
42	  retrieved_context: 5,
43	  dynamic_input: 6,
44	};
45	
46	export function compareBlocksByKind(a: PromptBlock, b: PromptBlock): number {
47	  return KIND_ORDER[a.kind] - KIND_ORDER[b.kind];
48	}
49	
50	/** Filter blocks down to the stable prefix (cache-eligible stable_* kinds). */
51	export function getStablePrefixBlocks(blocks: PromptBlock[]): PromptBlock[] {
52	  return blocks.filter(
53	    (b) =>
54	      b.kind === 'stable_system' ||
55	      b.kind === 'stable_tool_definition' ||
56	      b.kind === 'stable_schema' ||
57	      b.kind === 'output_contract',
58	  );
59	}
60	
61	/** Build a PromptBlock with the hash filled in correctly. */
62	export function makeBlock(args: {
63	  id: string;
64	  label: string;
65	  kind: PromptBlockKind;
66	  content: string;
67	  cacheEligible?: boolean;
68	  reasonIncluded: string;
69	}): PromptBlock {
70	  const cacheEligible =
71	    args.cacheEligible ??
72	    (args.kind === 'stable_system' ||
73	      args.kind === 'stable_tool_definition' ||
74	      args.kind === 'stable_schema' ||
75	      args.kind === 'output_contract');
76	  return {
77	    id: args.id,
78	    label: args.label,
79	    kind: args.kind,
80	    content: args.content,
81	    hash: hashContent(args.content),
82	    tokenEstimate: estimateTokens(args.content),
83	    cacheEligible,
84	    reasonIncluded: args.reasonIncluded,
85	  };
86	}
