1	import { createHash } from 'node:crypto';
2	import type { OraclePromptPlan, OracleTaskType, PromptBlock } from '../client/types';
3	
4	export interface VertexFileCacheSource {
5	  gcsUri?: string;
6	  localPath?: string;
7	  mimeType: string;
8	  fileName?: string;
9	  sourceHash?: string;
10	}
11	
12	export interface CacheHints {
13	  disableCache?: boolean;
14	  preferLongLivedCache?: boolean;
15	  preferExplicitCache?: boolean;
16	  cacheTtlSeconds?: number;
17	  expectedReuseCount?: number;
18	  persistProviderCacheRecord?: boolean;
19	  sourceDescription?: string;
20	  cleanupOwner?: string;
21	  createdByJobRunId?: string;
22	  latestPlannedReuseStep?: string;
23	  sessionCacheKey?: string;
24	  previousResponseId?: string;
25	  vertexFileCacheSource?: VertexFileCacheSource;
26	}
27	
28	export interface ProviderCacheOptions {
29	  messages?: Array<Record<string, unknown>>;
30	  cache?: CacheHints;
31	  [key: string]: unknown;
32	}
33	
34	export function estimateTextTokens(text: string): number {
35	  if (!text) return 0;
36	  return Math.ceil(text.length / 4);
37	}
38	
39	export function estimatePlanStableTokens(plan: OraclePromptPlan): number {
40	  const stableText = plan.blocks
41	    .filter((block) =>
42	      block.kind === 'stable_system' ||
43	      block.kind === 'stable_schema' ||
44	      block.kind === 'stable_tool_definition' ||
45	      block.kind === 'output_contract',
46	    )
47	    .map((block) => block.content)
48	    .join('\n\n');
49	  return estimateTextTokens(stableText);
50	}
51	
52	export function pickAnthropicCacheTtl(
53	  taskType: OracleTaskType,
54	  providerOptions?: Record<string, unknown>,
55	): '5m' | '1h' {
56	  const hints = getCacheHints(providerOptions);
57	  if (hints?.cacheTtlSeconds && hints.cacheTtlSeconds > 5 * 60) return '1h';
58	  if (hints?.preferLongLivedCache) return '1h';
59	  return taskType === 'interview_chat' ? '5m' : '1h';
60	}
61	
62	export function pickOpenAICacheRetention(
63	  taskType: OracleTaskType,
64	  providerOptions?: Record<string, unknown>,
65	): 'in_memory' | '24h' {
66	  const hints = getCacheHints(providerOptions);
67	  if (hints?.preferLongLivedCache) return '24h';
68	  if (hints?.cacheTtlSeconds && hints.cacheTtlSeconds > 10 * 60) return '24h';
69	  return taskType === 'interview_chat' ? 'in_memory' : '24h';
70	}
71	
72	export function pickVertexCacheTtlSeconds(
73	  taskType: OracleTaskType,
74	  providerOptions?: Record<string, unknown>,
75	): number {
76	  const hints = getCacheHints(providerOptions);
77	  if (typeof hints?.cacheTtlSeconds === 'number' && hints.cacheTtlSeconds > 0) {
78	    return Math.floor(hints.cacheTtlSeconds);
79	  }
80	  return taskType === 'interview_chat' ? 3600 : 86400;
81	}
82	
83	export function getCacheHints(
84	  providerOptions?: Record<string, unknown>,
85	): CacheHints | undefined {
86	  const cache = providerOptions?.cache;
87	  if (!cache || typeof cache !== 'object') return undefined;
88	  return cache as CacheHints;
89	}
90	
91	export function shouldDisableCache(providerOptions?: Record<string, unknown>): boolean {
92	  return getCacheHints(providerOptions)?.disableCache === true;
93	}
94	
95	export function normalizeMessageContentArray(
96	  content: unknown,
97	): Array<Record<string, unknown>> {
98	  if (Array.isArray(content)) {
99	    return content.map((part) => {
100	      if (part && typeof part === 'object') return { ...(part as Record<string, unknown>) };
101	      return { type: 'text', text: String(part) };
102	    });
103	  }
104	  if (typeof content === 'string') return [{ type: 'text', text: content }];
105	  if (content && typeof content === 'object') return [{ ...(content as Record<string, unknown>) }];
106	  return [{ type: 'text', text: String(content ?? '') }];
107	}
108	
109	export function markLastTextPartCacheable(
110	  content: Array<Record<string, unknown>>,
111	  ttl?: '5m' | '1h',
112	): Array<Record<string, unknown>> {
113	  const next = content.map((part) => ({ ...part }));
114	  for (let i = next.length - 1; i >= 0; i -= 1) {
115	    const part = next[i]!;
116	    const type = part.type;
117	    if (type === 'text' || type === undefined) {
118	      part.cache_control = ttl
119	        ? { type: 'ephemeral', ttl }
120	        : { type: 'ephemeral' };
121	      return next;
122	    }
123	  }
124	  if (next.length > 0) {
125	    next[next.length - 1]!.cache_control = ttl
126	      ? { type: 'ephemeral', ttl }
127	      : { type: 'ephemeral' };
128	  }
129	  return next;
130	}
131	
132	export function hashCacheKey(parts: Array<string | undefined | null>): string {
133	  return createHash('sha256')
134	    .update(parts.filter(Boolean).join('::'), 'utf8')
135	    .digest('hex');
136	}
137	
138	export interface FlattenedPlanSegments {
139	  systemPrompt: string;
140	  prefixContext: string;
141	  dynamicInput: string;
142	}
143	
144	export function splitPlanForCaching(plan: OraclePromptPlan): FlattenedPlanSegments {
145	  const stable: string[] = [];
146	  const prefix: string[] = [];
147	  const dynamic: string[] = [];
148	
149	  for (const block of plan.blocks) {
150	    if (isStableBlock(block)) stable.push(block.content);
151	    else if (block.kind === 'dynamic_input') dynamic.push(block.content);
152	    else prefix.push(block.content);
153	  }
154	
155	  return {
156	    systemPrompt: stable.join('\n\n'),
157	    prefixContext: prefix.join('\n\n'),
158	    dynamicInput: dynamic.join('\n\n'),
159	  };
160	}
161	
162	function isStableBlock(block: PromptBlock): boolean {
163	  return (
164	    block.kind === 'stable_system' ||
165	    block.kind === 'stable_schema' ||
166	    block.kind === 'stable_tool_definition' ||
167	    block.kind === 'output_contract'
168	  );
169	}
