222	  /**
223	   * Translate `providerOptions.messages` (a multi-turn array shaped for the
224	   * Vercel AI SDK / OpenAI chat format) into Vertex's `contents` shape, or
225	   * fall back to a single user turn when no override is present.
226	   */
227	  private buildContents(
228	    userMessage: string,
229	    providerOptions?: Record<string, unknown>,
230	  ): Content[] {
231	    const messages = providerOptions?.messages as
232	      | Array<{ role: 'user' | 'assistant' | 'system'; content: string }>
233	      | undefined;
234	    if (Array.isArray(messages) && messages.length > 0) {
235	      // Vertex uses 'model' instead of 'assistant'; system goes in
236	      // systemInstruction not contents.
237	      return messages
238	        .filter((m) => m.role !== 'system')
239	        .map((m) => ({
240	          role: m.role === 'assistant' ? 'model' : 'user',
241	          parts: [{ text: m.content }],
242	        }));
243	    }
244	    return [{ role: 'user', parts: [{ text: userMessage }] }];
245	  }
246	
247	  private async prepareExplicitCacheForText(
248	    plan: OraclePromptPlan,
249	    modelId: string,
250	    systemPrompt: string,
251	    contents: Content[],
252	    providerOptions?: Record<string, unknown>,
253	  ): Promise<{
254	    cacheName?: string;
255	    omitSystemInstruction: boolean;
256	      contentsForRequest: Content[];
257	      requestUserMessage?: string;
258	      lifecycleHandle?: CacheLifecycleHandle;
259	  } | null> {
260	    const hints = getCacheHints(providerOptions);
261	    const fileCache = await this.prepareExplicitFileCache(plan, modelId, systemPrompt, providerOptions);
262	    if (fileCache) {
263	      // The cached prefix already carries systemInstruction + the file artifact.
264	      // For multi-turn chat (interview route), send the FULL conversation as the
265	      // live contents on top of the cache so history is preserved. Only collapse
266	      // to the single dynamicInput turn when there is no conversation — e.g. a
267	      // single-shot text call whose document corpus is the whole input.
268	      const liveContents =
269	        contents.length > 0
270	          ? contents
271	          : [{ role: 'user' as const, parts: [{ text: fileCache.dynamicInput }] }];
272	      return {
273	        cacheName: fileCache.name,
274	        omitSystemInstruction: true,
275	        contentsForRequest: liveContents,
276	        requestUserMessage: fileCache.dynamicInput,
277	        lifecycleHandle: fileCache.lifecycleHandle,
278	      };
279	    }
280	    const prefixContents = contents.slice(0, -1);
281	    const latestTurn = contents[contents.length - 1];
282	    const prefixText = prefixContents
283	      .flatMap((content) => content.parts ?? [])
284	      .map((part) => String(part.text ?? ''))
285	      .join('\n');
286	    const stableTokens = estimatePlanStableTokens(plan);
287	    const prefixTokens = estimateTextTokens(prefixText);
288	    const shouldCreate =
289	      hints?.preferExplicitCache === true ||
290	      prefixTokens >= 2048 ||
291	      stableTokens >= 2048;
292	    if (!shouldCreate || !latestTurn) return null;
293	
294	    const cachePayload = prefixContents.length > 0
295	      ? { contents: prefixContents, includesSystemInstruction: !!systemPrompt }
296	      : { contents: [], includesSystemInstruction: !!systemPrompt };
297	    const sourceText = [systemPrompt, prefixContents.length > 0 ? prefixText : '']
298	      .filter(Boolean)
299	      .join('\n\n');
300	    const explicitCache = await this.getOrCreateExplicitCache({
301	      modelId,
302	      systemInstruction: systemPrompt || undefined,
303	      contents: cachePayload.contents,
304	      ttlSeconds: pickVertexCacheTtlSeconds(plan.taskType, providerOptions),
305	      cacheKey: hashCacheKey([
306	        modelId,
307	        plan.metadata.stablePrefixHash,
