540	  private async ensureVertexCacheFileUri(fileSource: VertexFileCacheSource): Promise<{
541	    fileUri: string;
542	    objectName?: string;
543	  } | null> {
544	    if (fileSource.gcsUri) return { fileUri: fileSource.gcsUri };
545	    if (!fileSource.localPath) return null;
546	    const bucketName = process.env.GOOGLE_VERTEX_CONTEXT_CACHE_GCS_BUCKET;
547	    if (!bucketName) {
548	      console.warn('[VertexGeminiAdapter] GOOGLE_VERTEX_CONTEXT_CACHE_GCS_BUCKET is unset; skipping file-backed cache path');
549	      return null;
550	    }
551	    const prefix = process.env.GOOGLE_VERTEX_CONTEXT_CACHE_GCS_PREFIX ?? 'oracle-context-cache';
552	    const objectName = `${prefix}/${fileSource.sourceHash ?? hashCacheKey([fileSource.localPath, fileSource.fileName])}-${fileSource.fileName ?? 'source'}`;
553	    const storage = this.getStorageClient();
554	    await storage.bucket(bucketName).upload(fileSource.localPath, {
555	      destination: objectName,
556	      metadata: {
557	        contentType: fileSource.mimeType,
558	      },
559	    });
560	    return {
561	      fileUri: `gs://${bucketName}/${objectName}`,
562	      objectName,
563	    };
564	  }
