979	/**
980	 * Flatten the OraclePromptPlan into a (systemPrompt, userMessage) pair.
981	 * Stable blocks become the system prompt; semi-stable / retrieved / dynamic
982	 * blocks concatenate into the user message in order. Preserves cacheable-
983	 * prefix ordering so provider-native cache machinery actually hits.
984	 */
985	export function flattenPlan(plan: OraclePromptPlan): {
986	  systemPrompt: string;
987	  userMessage: string;
988	} {
989	  const { systemPrompt, prefixContext, dynamicInput } = splitPlanForCaching(plan);
990	  return {
991	    systemPrompt,
