996	/**
997	 * Convert a Zod schema (or any unknown — we duck-type) to standard JSON
998	 * Schema 2020-12. Falls back to assuming the input is already JSON Schema if
999	 * it doesn't look like a Zod object.
1000	 */
1001	export function zodToJsonSchema(schema: unknown): unknown {
1002	  const s = schema as { _def?: unknown };
1003	  if (s && typeof s === 'object' && '_def' in s) {
1004	    return z.toJSONSchema(schema as ZodTypeAny);
1005	  }
1006	  return schema;
1007	}
