1009	/**
1010	 * Best-effort Zod runtime validation. Returns the validated value on success,
1011	 * or null if the input doesn't look like a Zod schema (so the caller can fall
1012	 * back to the raw parsed JSON). Throws on Zod validation failure — the caller
1013	 * decides what to do.
1014	 */
1015	export function tryZodParse<T>(schema: unknown, value: unknown): T | null {
1016	  const s = schema as { safeParse?: (v: unknown) => { success: boolean; data: T; error: unknown } };
1017	  if (s && typeof s === 'object' && typeof s.safeParse === 'function') {
1018	    const result = s.safeParse(value);
1019	    if (!result.success) return null;
1020	    return result.data;
1021	  }
1022	  return null;
1023	}
