1	/**
2	 * buildStandardAdapters() — single source of truth for the production adapter
3	 * map. Used by /api/chat and every Trigger.dev worker so that adding a new
4	 * provider only touches this file (plus the route catalog).
5	 *
6	 * Tolerant of missing env vars: if any adapter's constructor throws (e.g.
7	 * DEEPSEEK_API_KEY isn't set yet), that adapter is omitted instead of taking
8	 * down the whole map. Dispatch to an unregistered adapter still fails fast
9	 * inside ModelRouter — this only prevents one missing key from breaking
10	 * every endpoint at boot.
11	 */
12	
13	import { AnthropicAdapter } from '../providers/anthropic-adapter';
14	import { VertexGeminiAdapter } from '../providers/vertex-gemini-adapter';
15	import { OpenAIAdapter } from '../providers/openai-adapter';
16	import { DeepSeekAdapter } from '../providers/deepseek-adapter';
17	import { QwenAdapter } from '../providers/qwen-adapter';
18	import type { ProviderAdapterMap } from '../routing/model-router';
19	import type { OracleProvider } from '../routes';
20	import type { OracleProviderAdapter } from '../providers/types';
21	
22	const IS_PROD = process.env.NODE_ENV === 'production';
23	
24	function tryAdd(
25	  map: ProviderAdapterMap,
26	  key: OracleProvider,
27	  factory: () => OracleProviderAdapter,
28	): void {
29	  try {
30	    map[key] = factory();
31	  } catch (err) {
32	    if (!IS_PROD) {
33	      // eslint-disable-next-line no-console
34	      console.warn(
35	        `[buildStandardAdapters] skipped ${key}: ${err instanceof Error ? err.message : String(err)}`,
36	      );
37	    }
38	  }
39	}
