41	export function buildStandardAdapters(): ProviderAdapterMap {
42	  const map: ProviderAdapterMap = {};
43	  tryAdd(map, 'anthropic', () => new AnthropicAdapter());
44	  tryAdd(map, 'vertex',    () => new VertexGeminiAdapter());
45	  tryAdd(map, 'openai',    () => new OpenAIAdapter());
46	  tryAdd(map, 'deepseek',  () => new DeepSeekAdapter());
47	  tryAdd(map, 'qwen',      () => new QwenAdapter());
48	  return map;
