29	}
30	
31	export interface GenerateTextArgs {
32	  plan: OraclePromptPlan;
33	  route: OracleModelRoute;
34	  /**
35	   * Optional generic escape hatch for adapter-specific parameters that
36	   * don't fit into the OraclePromptPlan. The chat route uses this for:
37	   *   - `tools` (Vercel AI SDK ToolSet)
38	   *   - `stopWhen` (stepCountIs(N) for multi-turn tool calls)
39	   *   - `temperature`
40	   *   - `messages` — multi-turn conversation history that overrides the
41	   *     single (system, user-message) shape flattened from the plan
42	   *
43	   * Adapters that don't support a given option ignore it silently. The
44	   * shape is unconstrained on purpose to avoid leaking provider-specific
45	   * types into the OracleAIClient surface.
46	   */
47	  providerOptions?: Record<string, unknown>;
48	}
