50	// ─── Batch API contract ─────────────────────────────────────────────────────
51	//
52	// Provider Batch APIs (OpenAI Batch, Vertex Batch Prediction, Anthropic
53	// Message Batches) run async at ~50% sync pricing with a 24-hour SLA. The
54	// adapter contract is intentionally provider-agnostic; provider-specific
55	// identifiers (OpenAI file IDs, Vertex GCS URIs) flow through the opaque
56	// `providerMetadata` field which the caller persists to
57	// `provider_batch_jobs.provider_metadata_json` and passes back at retrieve
58	// time. See DECISIONS.md D14.
59	
60	export interface BatchRequest {
61	  /**
62	   * Caller-supplied identifier echoed back in `BatchResultItem.customId`.
63	   * The caller uses it to map results to its own per-input rows
64	   * (e.g. extraction_batches.id).
65	   */
66	  customId: string;
67	  plan: OraclePromptPlan;
68	  /** Provider-specific per-request options (rare; usually empty). */
69	  providerOptions?: Record<string, unknown>;
70	}
71	
72	export interface SubmitBatchArgs {
73	  route: OracleModelRoute;
74	  requests: BatchRequest[];
75	  /**
76	   * Structured-output JSON Schema applied uniformly to every request.
77	   * Adapters translate per provider: Anthropic → forced tool call,
78	   * OpenAI → response_format json_schema strict, Vertex → responseJsonSchema.
79	   * If omitted, the batch is treated as generateText (free-form output).
80	   */
81	  jsonSchema?: unknown;
82	  /**
83	   * Provider-specific batch-level options. Examples:
84	   *  - OpenAI: { completionWindow?: '24h' }
85	   *  - Vertex: { inputGcsUri?, outputGcsUri? } (adapter generates if omitted)
86	   */
87	  providerOptions?: Record<string, unknown>;
88	}
89	
90	export interface SubmitBatchResult {
91	  /** The provider's batch identifier. Used to poll status later. */
92	  providerBatchId: string;
93	  /**
94	   * Opaque provider-specific metadata. Persist verbatim and pass back at
95	   * retrieve time. Examples:
96	   *  - OpenAI: { inputFileId, outputFileId?, errorFileId? }
97	   *  - Vertex: { inputGcsUri, outputGcsUri }
98	   *  - Anthropic: {} (batch ID is sufficient)
99	   */
100	  providerMetadata: Record<string, unknown>;
101	}
102	
103	export type BatchStatus =
104	  | 'submitted'
105	  | 'in_progress'
106	  | 'completed'
107	  | 'failed'
108	  | 'expired'
109	  | 'canceled';
110	
111	export interface BatchResultItem {
112	  /** Echoed from the original BatchRequest.customId. */
113	  customId: string;
114	  success: boolean;
115	  /** Set for generateText-style outputs (no jsonSchema). */
116	  text?: string;
117	  /** Set for generateObject-style outputs — parsed JSON (NOT yet Zod-validated). */
118	  output?: unknown;
119	  /** Provider-reported token usage for the individual request. */
120	  usage?: OracleUsage;
121	  /** Present when success === false. */
122	  error?: string;
123	}
124	
125	export interface RetrieveBatchArgs {
126	  providerBatchId: string;
127	  /** The `providerMetadata` returned by submitBatch, persisted by the caller. */
128	  providerMetadata: Record<string, unknown>;
129	  route: OracleModelRoute;
130	}
131	
132	export interface RetrieveBatchResult {
133	  status: BatchStatus;
134	  /** Populated when status is 'completed' (and optionally partial 'failed'). */
135	  results?: BatchResultItem[];
136	  /** Provider's reported counts when available. */
137	  requestCount?: number;
138	  completedCount?: number;
139	  failedCount?: number;
140	  /** Set when status is 'failed' / 'expired' / 'canceled' and there's a top-level cause. */
141	  error?: string;
142	}
143	
144	export interface OracleProviderAdapter {
145	  readonly provider: OracleProvider;
146	
147	  generateObject<TSchema, TOutput>(
148	    args: GenerateObjectArgs<TSchema>,
149	  ): Promise<OracleObjectResult<TOutput>>;
150	
151	  generateText(args: GenerateTextArgs): Promise<OracleTextResult>;
152	
153	  /** Optional — only adapters that natively support streaming implement this. */
154	  streamText?(args: GenerateTextArgs): AsyncIterable<{ delta: string; usage?: OracleUsage }>;
155	
156	  /**
157	   * Optional — submit a batch of requests to the provider's Batch API.
158	   * Adapters that don't implement this aren't usable in batch mode; the
159	   * two-phase extraction worker falls back to sync for those providers.
160	   */
161	  submitBatch?(args: SubmitBatchArgs): Promise<SubmitBatchResult>;
162	
163	  /** Optional — poll status and retrieve results once status === 'completed'. */
164	  retrieveBatch?(args: RetrieveBatchArgs): Promise<RetrieveBatchResult>;
165	}
166	
167	/** True when the adapter implements the optional Batch API methods. */
168	export function supportsBatch(adapter: OracleProviderAdapter): boolean {
169	  return typeof adapter.submitBatch === 'function'
170	    && typeof adapter.retrieveBatch === 'function';
171	}
172	
173	/**
174	 * Sentinel error thrown by stub adapters when their real implementation has
175	 * not yet been built. OracleAIClient may catch this and route to a fallback
176	 * adapter or to the mock adapter under test mode.
177	 */
178	export class ProviderAdapterNotImplementedError extends Error {
179	  constructor(public readonly provider: OracleProvider) {
180	    super(
181	      `Provider adapter for "${provider}" is not yet implemented. R2 ships the interface and stubs only; real SDK integration lands in R3+. Use OracleAIClient in test mode to exercise the call shape.`,
182	    );
183	    this.name = 'ProviderAdapterNotImplementedError';
184	  }
185	}
