1	/**
2	 * ContextCompiler — assembles an OraclePromptPlan with blocks in the correct
3	 * order, computes the cache-friendly hashes, and validates that no dynamic
4	 * content has been placed before the stable prefix.
5	 *
6	 * This compiler does NOT make a provider call. It only produces the plan.
7	 * The provider adapter receives the plan and renders it into a provider-
8	 * specific request shape.
9	 *
10	 * Per docs/oracle/02-provider-native-ai-architecture.md "ContextCompiler rules":
11	 *   1. Stable system/task instructions.
12	 *   2. Stable tool definitions.
13	 *   3. Stable output schema or Zod/JSON schema description.
14	 *   4. Semi-stable domain/taxonomy context.
15	 *   5. Retrieved context.
16	 *   6. Dynamic input.
17	 *   7. Retry-specific or validation-error suffix.
18	 */
19	
20	import type {
21	  OraclePromptPlan,
22	  PromptBlock,
23	  PromptPlanMetadata,
24	  OracleTaskType,
25	  OutputContract,
26	} from '../client/types';
27	import {
28	  compareBlocksByKind,
29	  getStablePrefixBlocks,
30	  hashBlockSequence,
31	  hashContent,
32	} from './prompt-blocks';
33	
34	export interface CompileArgs {
35	  taskType: OracleTaskType;
36	  routeId: string;
37	  promptVersion: string;
38	  schemaVersion?: string;
39	  /** Blocks in any order; the compiler sorts them by kind. */
40	  blocks: PromptBlock[];
41	  outputContract?: OutputContract;
42	  /** Optional metadata to merge into the plan. */
43	  observability?: Partial<
44	    Pick<
45	      PromptPlanMetadata,
46	      | 'includedMessageIds'
47	      | 'includedDocumentChunkIds'
48	      | 'includedClaimIds'
49	      | 'includedGapIds'
50	      | 'includedContradictionIds'
51	      | 'retrievalPlanId'
52	      | 'selectedDomains'
53	      | 'selectedSourceTypes'
54	      | 'selectedProcessStages'
55	      | 'selectedEntityIds'
56	    >
57	  >;
58	}
59	
60	export class ContextCompiler {
61	  compile(args: CompileArgs): OraclePromptPlan {
62	    if (args.blocks.length === 0) {
63	      throw new Error('ContextCompiler.compile requires at least one PromptBlock.');
64	    }
65	
66	    // Sort by kind. The kind ordering enforces stable-before-dynamic.
67	    const ordered = [...args.blocks].sort(compareBlocksByKind);
68	
69	    // Defensive invariant: a dynamic_input block must not precede any stable_* block.
70	    this.assertStableBeforeDynamic(ordered);
71	
72	    const stableBlocks = getStablePrefixBlocks(ordered);
73	    const semiStableBlocks = ordered.filter((b) => b.kind === 'semi_stable_domain_context');
74	    const retrievedBlocks = ordered.filter((b) => b.kind === 'retrieved_context');
75	    const dynamicBlocks = ordered.filter((b) => b.kind === 'dynamic_input');
76	
77	    const stablePrefixHash = hashBlockSequence(stableBlocks);
78	    const semiStableContextHash = semiStableBlocks.length > 0 ? hashBlockSequence(semiStableBlocks) : undefined;
79	    const retrievedContextHash = retrievedBlocks.length > 0 ? hashBlockSequence(retrievedBlocks) : undefined;
80	    const dynamicInputHash = dynamicBlocks.length > 0 ? hashBlockSequence(dynamicBlocks) : hashContent('');
81	
82	    const toolSchemaBlock = ordered.find((b) => b.kind === 'stable_tool_definition');
83	    const outputSchemaBlock = ordered.find((b) => b.kind === 'stable_schema' || b.kind === 'output_contract');
84	
85	    const metadata: PromptPlanMetadata = {
86	      stablePrefixHash,
87	      semiStableContextHash,
88	      retrievedContextHash,
89	      dynamicInputHash,
90	      toolSchemaHash: toolSchemaBlock?.hash,
91	      outputSchemaHash: outputSchemaBlock?.hash,
92	      ...args.observability,
93	    };
94	
95	    return {
96	      taskType: args.taskType,
97	      routeId: args.routeId,
98	      promptVersion: args.promptVersion,
99	      schemaVersion: args.schemaVersion,
100	      blocks: ordered,

150	    const toolUse = response.content.find((b) => b.type === 'tool_use');
151	    if (!toolUse || toolUse.type !== 'tool_use') {
152	      throw new Error(
