175	   * The batch ID alone is sufficient to retrieve results later, so
176	   * providerMetadata is an empty object (see types.ts SubmitBatchResult).
177	   */
178	  async submitBatch(args: SubmitBatchArgs): Promise<SubmitBatchResult> {
179	    const { route, requests, jsonSchema } = args;
180	    const thinking = thinkingParam(route.reasoningEffort, this.defaultMaxTokens);
181	    const TOOL_NAME = 'output_structured';
182	    const structuredTool = jsonSchema
183	      ? {
184	          name: TOOL_NAME,
185	          description:
186	            'Return the structured output. You MUST use this tool exactly once and never reply in plain text.',
187	          input_schema: jsonSchema as Anthropic.Tool.InputSchema,
188	        }
189	      : undefined;
190	
191	    const sdkRequests = requests.map((req) => {
192	      const { systemPrompt, userMessage } = flattenPlan(req.plan);
193	      const providerOptions = req.providerOptions;
194	      const params: MessageCreateParamsNonStreaming = {
195	        model: route.modelId,
196	        max_tokens: this.defaultMaxTokens,
197	        temperature: thinking
198	          ? 1
199	          : structuredTool
200	            ? 0.1
201	            : (typeof providerOptions?.temperature === 'number'
202	              ? providerOptions.temperature
203	              : undefined) as number | undefined,
204	        system: systemPrompt,
205	        messages: [{ role: 'user', content: userMessage }],
206	        ...(structuredTool
207	          ? {
208	              tools: [structuredTool],
209	              tool_choice: { type: 'tool', name: TOOL_NAME } as const,
210	            }
211	          : {}),
212	        ...(thinking ? { thinking } : {}),
213	      };
214	      return { custom_id: req.customId, params };
215	    });
216	
217	    const batch = await this.client.messages.batches.create({ requests: sdkRequests });
218	    return {
219	      providerBatchId: batch.id,
220	      providerMetadata: {},
221	    };
222	  }
223	
224	  /**
225	   * Poll status and, when terminal, stream the per-request results JSONL.
226	   * Each line carries the caller's `custom_id` so results map back to the
227	   * originating BatchRequest.
228	   *
229	   * Anthropic processing_status:
230	   *   in_progress | canceling → still running ('in_progress')
231	   *   ended                   → terminal; iterate results to build items
232	   *
233	   * Per-item `result.type`:
234	   *   succeeded → success; pull text or tool_use block
235	   *   errored   → failure with error.message
236	   *   canceled  → failure 'request canceled'
237	   *   expired   → failure 'request expired'
238	   */
239	  async retrieveBatch(args: RetrieveBatchArgs): Promise<RetrieveBatchResult> {
240	    const { providerBatchId } = args;
241	    const batch = await this.client.messages.batches.retrieve(providerBatchId);
242	    const counts = batch.request_counts;
243	    const requestCount =
244	      counts.processing + counts.succeeded + counts.errored + counts.canceled + counts.expired;
245	    const completedCount = counts.succeeded;
246	    const failedCount = counts.errored + counts.canceled + counts.expired;
247	
248	    if (batch.processing_status !== 'ended') {
249	      return {
250	        status: 'in_progress' as BatchStatus,
251	        requestCount,
252	        completedCount,
253	        failedCount,
254	      };
255	    }
256	
257	    const results: BatchResultItem[] = [];
258	    const stream = await this.client.messages.batches.results(providerBatchId);
259	    for await (const entry of stream as AsyncIterable<MessageBatchIndividualResponse>) {
260	      results.push(this.normalizeBatchResultItem(entry));
261	    }
262	
263	    return {
264	      status: 'completed',
265	      results,
266	      requestCount,
267	      completedCount,
268	      failedCount,
269	    };
270	  }
271	
272	  private normalizeBatchResultItem(entry: MessageBatchIndividualResponse): BatchResultItem {
273	    const customId = entry.custom_id;
274	    const result = entry.result;
275	    if (result.type === 'errored') {
276	      return {
277	        customId,
278	        success: false,
279	        error: result.error?.error?.message ?? 'errored',
280	      };
281	    }
282	    if (result.type === 'canceled') {
283	      return { customId, success: false, error: 'request canceled' };
284	    }
285	    if (result.type === 'expired') {
286	      return { customId, success: false, error: 'request expired' };
287	    }
288	    // succeeded
289	    const message = result.message;
290	    const usage = this.normalizeUsage(message, 0);
291	    const toolUse = message.content.find((b) => b.type === 'tool_use');
292	    if (toolUse && toolUse.type === 'tool_use') {
293	      return { customId, success: true, output: toolUse.input, usage };
294	    }
295	    return { customId, success: true, text: this.extractText(message), usage };
296	  }
297	
298	  /**
299	   * Build the system field. When caching is enabled and the system prompt is
300	   * non-empty, use the array-of-blocks form so we can attach
301	   * cache_control: { type: 'ephemeral' }. Otherwise pass the plain string.
302	   */
303	  private buildSystem(
304	    plan: GenerateTextArgs['plan'],
305	    systemPrompt: string,
306	    providerOptions?: Record<string, unknown>,
307	    ttl?: '5m' | '1h',
308	  ): string | Anthropic.TextBlockParam[] {
309	    if (!this.enableSystemPromptCache || systemPrompt.length === 0 || shouldDisableCache(providerOptions)) {
310	      return systemPrompt;
311	    }
312	    const minTokens = anthropicCacheMinTokens(plan.routeId);
313	    const stableTokens = estimatePlanStableTokens(plan);
314	    if (stableTokens < minTokens) return systemPrompt;
315	    return [
316	      {
317	        type: 'text',
318	        text: systemPrompt,
319	        cache_control: ttl ? { type: 'ephemeral', ttl } : { type: 'ephemeral' },
320	      },
321	    ];
322	  }
323	
324	  /**
325	   * Build the messages array. If the caller passed a multi-turn `messages`
326	   * override via providerOptions (chat route does this for R8 multi-turn),
327	   * pass it through; otherwise wrap the flattened user message in a single
328	   * user turn.
329	   */
330	  private buildMessages(
331	    plan: GenerateTextArgs['plan'],
332	    userMessage: string,
333	    providerOptions?: Record<string, unknown>,
334	    ttl?: '5m' | '1h',
335	  ): Anthropic.MessageParam[] {
